// TCP connection handler that safely deserializes incoming data
class ConnectionHandler(processor: ActorRef) extends Actor with ActorLogging {
  import Tcp._

  private val MaxMessageSize = 1024 * 1024 // 1MB limit
  private var buffer = ByteString.empty

  def receive: Receive = {
    case Received(data) =>
      buffer ++= data

      if (buffer.size > MaxMessageSize) {
        log.warning("Message too large, closing connection")
